const fs = require('fs');
const path = require('path');
const { exec } = require('child_process');

// Configure your paths here. 
const inputDir = '/data/Automation/Sumary Input';
const outputDir = '/data/Automation/Summary Output';
const introPath = '/data/Automation/intro.mp3';
const outroPath = '/data/Automation/outro.mp3';

// Wrap exec in a promise for async execution
const execAsync = (command) => new Promise((resolve, reject) => {
    exec(command, (error, stdout, stderr) => {
        if (error) {
            reject(error);
            return;
        }
        resolve(stdout || stderr);
    });
});

function walkSync(dir, filelist = []) {
    if (!fs.existsSync(dir)) return filelist;
    const files = fs.readdirSync(dir);
    for (const file of files) {
        const filepath = path.join(dir, file);
        if (fs.statSync(filepath).isDirectory()) {
            walkSync(filepath, filelist);
        } else {
            filelist.push(filepath);
        }
    }
    return filelist;
}

const allFiles = walkSync(inputDir).filter(f => f.toLowerCase().endsWith('.mp3'));
const hasIntro = fs.existsSync(introPath);
const hasOutro = fs.existsSync(outroPath);

const results = [];

// Helper to process a single file asynchronously
async function processFile(inputFile) {
    const relPath = path.relative(inputDir, inputFile);
    const outputFile = path.join(outputDir, relPath);
    const outputDirPath = path.dirname(outputFile);

    if (!fs.existsSync(outputDirPath)) {
        fs.mkdirSync(outputDirPath, { recursive: true });
    }

    let cmd = 'ffmpeg -y ';
    let filter = [];
    let inputs = [];
    let idx = 0;

    if (hasIntro) {
       inputs.push(`-i "${introPath}"`);
       filter.push(`[${idx}:a]`);
       idx++;
    }

    inputs.push(`-i "${inputFile}"`);
    filter.push(`[${idx}:a]`);
    idx++;

    if (hasOutro) {
       inputs.push(`-i "${outroPath}"`);
       filter.push(`[${idx}:a]`);
       idx++;
    }

    try {
        if (idx === 1) {
            // Just copy the file
            fs.copyFileSync(inputFile, outputFile);
            results.push({ file: relPath, status: 'copied' });
        } else {
            const filterStr = filter.join('') + `concat=n=${idx}:v=0:a=1[out]`;
            cmd += inputs.join(' ') + ` -filter_complex "${filterStr}" -map "[out]" "${outputFile}"`;
            await execAsync(cmd);
            results.push({ file: relPath, status: 'merged' });
        }
    } catch(err) {
        results.push({ file: relPath, status: 'error', error: err.message, cmd: cmd });
    }
}

// Verify ffmpeg exists in the environment
try {
    await execAsync('ffmpeg -version');
} catch(err) {
    return [{ json: { error: 'CRITICAL ERROR: ffmpeg is not installed inside the n8n docker container', details: err.message } }];
}

// Process files concurrently in chunks of 5
const concurrencyLimit = 5;
for (let i = 0; i < allFiles.length; i += concurrencyLimit) {
    const batch = allFiles.slice(i, i + concurrencyLimit);
    await Promise.all(batch.map(f => processFile(f)));
}

return [{ json: { processedCount: results.length, introFound: hasIntro, outroFound: hasOutro, details: results } }];
